def encode_saml_request(saml_request):
    compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded = base64.b64encode(compressed).decode('utf-8')
    return encoded


def decode_saml_response(saml_response_b64):
    decoded = base64.b64decode(saml_response_b64)
    return decoded.decode('utf-8')


def parse_saml_response(saml_xml):
    root = ET.fromstring(saml_xml)
    
    response_data = {
        'valid': False,
        'assertions': [],
        'status': None,
        'errors': []
    }
    
    status_code = root.find('.//samlp:StatusCode', SAML_NAMESPACES)
    if status_code is not None:
        response_data['status'] = status_code.get('Value')
        if 'Success' not in response_data['status']:
            response_data['errors'].append(f"SAML Response status not successful: {response_data['status']}")
            return response_data
    
    assertions = root.findall('.//saml:Assertion', SAML_NAMESPACES)
    
    if not assertions:
        response_data['errors'].append('No assertions found in SAML response')
        return response_data
    
    for assertion in assertions:
        assertion_data = parse_assertion(assertion)
        if assertion_data:
            response_data['assertions'].append(assertion_data)
    
    if response_data['assertions']:
        response_data['valid'] = True
    else:
        response_data['errors'].append('No valid assertions could be parsed')
    
    return response_data


def parse_assertion(assertion):
    assertion_data = {
        'subject': None,
        'attributes': {},
        'conditions': {},
        'authn_statement': {}
    }
    
    subject = assertion.find('.//saml:Subject/saml:NameID', SAML_NAMESPACES)
    if subject is not None:
        assertion_data['subject'] = {
            'name_id': subject.text,
            'format': subject.get('Format'),
            'name_qualifier': subject.get('NameQualifier')
        }
    
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    if conditions is not None:
        assertion_data['conditions'] = {
            'not_before': conditions.get('NotBefore'),
            'not_on_or_after': conditions.get('NotOnOrAfter')
        }
        
        audience = conditions.find('.//saml:Audience', SAML_NAMESPACES)
        if audience is not None:
            assertion_data['conditions']['audience'] = audience.text
    
    authn_statement = assertion.find('.//saml:AuthnStatement', SAML_NAMESPACES)
    if authn_statement is not None:
        assertion_data['authn_statement'] = {
            'authn_instant': authn_statement.get('AuthnInstant'),
            'session_index': authn_statement.get('SessionIndex')
        }
        
        authn_context = authn_statement.find('.//saml:AuthnContextClassRef', SAML_NAMESPACES)
        if authn_context is not None:
            assertion_data['authn_statement']['authn_context'] = authn_context.text
    
    attribute_statements = assertion.findall('.//saml:AttributeStatement/saml:Attribute', SAML_NAMESPACES)
    
    for attribute in attribute_statements:
        attr_name = attribute.get('Name')
        attr_friendly_name = attribute.get('FriendlyName')
        
        attr_values = []
        for attr_value in attribute.findall('saml:AttributeValue', SAML_NAMESPACES):
            if attr_value.text:
                attr_values.append(attr_value.text)
        
        key = attr_friendly_name if attr_friendly_name else attr_name
        
        if len(attr_values) == 1:
            assertion_data['attributes'][key] = attr_values[0]
        elif len(attr_values) > 1:
            assertion_data['attributes'][key] = attr_values
    
    return assertion_data


def validate_assertion_conditions(assertion_data):
    errors = []
    
    if 'conditions' in assertion_data:
        conditions = assertion_data['conditions']
        current_time = datetime.utcnow()
        
        if 'not_before' in conditions and conditions['not_before']:
            not_before = datetime.fromisoformat(conditions['not_before'].replace('Z', '+00:00'))
            if current_time < not_before.replace(tzinfo=None):
                errors.append(f"Assertion not yet valid (NotBefore: {conditions['not_before']})")
        
        if 'not_on_or_after' in conditions and conditions['not_on_or_after']:
            not_on_or_after = datetime.fromisoformat(conditions['not_on_or_after'].replace('Z', '+00:00'))
            if current_time >= not_on_or_after.replace(tzinfo=None):
                errors.append(f"Assertion expired (NotOnOrAfter: {conditions['not_on_or_after']})")
        
        if 'audience' in conditions and conditions['audience']:
            if conditions['audience'] != SP_ENTITY_ID:
                errors.append(f"Audience mismatch. Expected: {SP_ENTITY_ID}, Got: {conditions['audience']}")
    
    return errors


def create_user_session(assertion_data):
    session.permanent = True
    session['authenticated'] = True
    session['saml_session_index'] = assertion_data.get('authn_statement', {}).get('session_index')
    session['saml_name_id'] = assertion_data.get('subject', {}).get('name_id')
    session['saml_name_id_format'] = assertion_data.get('subject', {}).get('format')
    
    attributes = assertion_data.get('attributes', {})
    session['user_attributes'] = attributes
    
    session['user_id'] = attributes.get('uid') or attributes.get('email') or assertion_data.get('subject', {}).get('name_id')
    session['email'] = attributes.get('email') or attributes.get('mail')
    session['first_name'] = attributes.get('givenName') or attributes.get('firstName')
    session['last_name'] = attributes.get('sn') or attributes.get('surname') or attributes.get('lastName')
    session['display_name'] = attributes.get('displayName') or attributes.get('cn')
    session['groups'] = attributes.get('groups') or attributes.get('memberOf') or []
    
    session['login_time'] = datetime.utcnow().isoformat()


