@app.route('/acs', methods=['POST'])
def assertion_consumer_service():
    saml_response_b64 = request.form.get('SAMLResponse')
    
    if not saml_response_b64:
        return jsonify({'error': 'No SAMLResponse in request'}), 400
    
    try:
        saml_xml = decode_saml_response(saml_response_b64)
    except Exception as e:
        return jsonify({'error': f'Failed to decode SAML response: {str(e)}'}), 400
    
    try:
        response_data = parse_saml_response(saml_xml)
    except Exception as e:
        return jsonify({'error': f'Failed to parse SAML response: {str(e)}'}), 400
    
    if not response_data['valid']:
        return jsonify({
            'error': 'Invalid SAML response',
            'details': response_data['errors']
        }), 400
    
    if not response_data['assertions']:
        return jsonify({'error': 'No assertions found in SAML response'}), 400
    
    assertion_data = response_data['assertions'][0]
    
    validation_errors = validate_assertion_conditions(assertion_data)
    if validation_errors:
        return jsonify({
            'error': 'Assertion validation failed',
            'details': validation_errors
        }), 400
    
    create_user_session(assertion_data)
    
    return redirect(url_for('profile'))


